const items = $input.all();

function parseToMinutes(published) {
  if (!published) return Infinity;

  let cleaned = published
    .replace(/^(Premiered|Streamed)\s+/i, '')
    .replace(/^New\s*/i, '')
    .trim();

  const match = cleaned.match(/^(\d+)\s+(second|minute|hour|day|week|month|year)s?\s+ago$/i);

  if (match) {
    const value = parseInt(match[1]);
    const unit = match[2].toLowerCase();

    const multipliers = {
      second: 1 / 60,
      minute: 1,
      hour: 60,
      day: 1440,
      week: 10080,
      month: 43200,
      year: 525600
    };

    return value * (multipliers[unit] || Infinity);
  }

  const dateAttempt = new Date(cleaned);
  if (!isNaN(dateAttempt.getTime())) {
    const diffMs = Date.now() - dateAttempt.getTime();
    return Math.max(0, diffMs / 60000);
  }

  return Infinity;
}

const maxMinutes = 1440;

return items
  .map(item => {
    const minutesAgo = parseToMinutes(item.json.published_date);
    return {
      json: {
        ...item.json,
        minutes_ago: Math.round(minutesAgo)
      }
    };
  })
  .filter(item => item.json.minutes_ago <= maxMinutes);

const items = $input.all();
const VIRALITY_THRESHOLD = 2000;

return items.map(item => {
  const views = parseInt(item.json['VIDEO VIEWS']) || 0;
  const likes = parseInt(item.json['VIDEO LIKES']) || 0;
  const subscribers = parseInt(item.json['SUBSCRIBER COUNT']) || 1;

  const minutesMatch = (item.json.PUBDATE || '').match(/^(\d+)/);
  const minutesAgo = minutesMatch ? parseInt(minutesMatch[1]) : 1440;

  const viewVelocity = views / Math.max(minutesAgo, 60);
  const engagementRatio = (likes / Math.max(views, 1)) * 100;
  const subscriberOutperformance = views / Math.max(subscribers, 1);

  const viralityScore = viewVelocity * (1 + engagementRatio) * (1 + subscriberOutperformance);

  return {
    json: {
      ...item.json,
      virality_score: Math.round(viralityScore * 1000) / 1000,
      is_viral: viralityScore >= VIRALITY_THRESHOLD ? 'VIRAL' : 'NOT VIRAL'
    }
  };
});

