const sources = $input.first().json.output.sources;

const seen = new Set();
const deduped = sources.filter(source => {
  try {
    const key = source.url
      .replace(/^https?:\/\//, '')
      .replace(/\/+$/, '')
      .replace(/\?.*$/, '');
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  } catch {
    return false;
  }
});

const tier1Domains = [
  'bloomberg.com', 'reuters.com', 'wsj.com', 'ft.com',
  'imf.org', 'oecd.org', 'federalreserve.gov', 'sec.gov'
];

const scored = deduped.map(source => {
  const isTier1 = tier1Domains.some(d => source.url.includes(d));
  const domainScore = isTier1 ? 2 : 1;
  const tagScore = { data: 3, opposing_view: 3, etf_context: 2, deep_dive: 2, historical_parallel: 1 };
  return { ...source, _score: domainScore + (tagScore[source.tag] || 1) };
});

scored.sort((a, b) => b._score - a._score);

const final = scored.slice(0, 6);

return final.map(source => ({
  json: {
    url: source.url,
    title: source.title,
    justification: source.justification,
    tag: source.tag
  }
}));

