const row = $input.first().json;
const blocks = JSON.parse(row.BLOCKS_JSON);

const imagePlaceholders = blocks
  .map((block, index) => ({ ...block, originalIndex: index }))
  .filter(block => block.type === 'image' && block.src === 'PLACEHOLDER');

return [{
  json: {
    ...row,
    blocks,
    imagePlaceholders,
    imageCount: imagePlaceholders.length
  }
