const items = $input.all();
const fallback = 'https://images.unsplash.com/photo-1611974789855-9c2a0a7236a3?w=1200';

return items.map(item => {
  const selection = item.json.output || {};
  const candidates = item.json.candidates || [];
  const alt = item.json.alt || '';
  const caption = item.json.caption || '';
  const originalIndex = item.json.originalIndex;

  let finalSrc = fallback;
  let finalSource = '';

  if (selection.acceptable && selection.selected_index > 0) {
    const picked = candidates[selection.selected_index - 1];
    if (picked && picked.url) {
      finalSrc = picked.url;
      finalSource = picked.source || '';
    }
  }

  return {
    json: {
      originalIndex,
      src: finalSrc,
      alt,
      caption,
      source: finalSource,
      reasoning: selection.reasoning || 'No acceptable image found.'
    }
  };
});

const images = $input.all().map(item => item.json);

return [{
  json: {
    resolvedImages: images
  }
}];

const merged = $input.first().json;
const resolvedImages = merged.resolvedImages;
const blocksJson = merged.BLOCKS_JSON;
const blocks = JSON.parse(blocksJson);

let placeholderIndex = 0;

for (let i = 0; i < blocks.length; i++) {
  if (blocks[i].type === 'image' && blocks[i].src === 'PLACEHOLDER') {
    const resolved = resolvedImages.find(img => img.originalIndex === placeholderIndex);
    if (resolved) {
      blocks[i].src = resolved.src;
      if (resolved.source) {
        blocks[i].caption = (blocks[i].caption || '') +
          (blocks[i].caption ? ' | ' : '') +
          'Source: ' + resolved.source;
      }
    }
    placeholderIndex++;
  }
}

let featureImage = '';
for (let i = 0; i < blocks.length; i++) {
  if (blocks[i].type === 'image' && blocks[i].src && blocks[i].src !== 'PLACEHOLDER') {
    featureImage = blocks[i].src;
    break;
  }
}

return [{
  json: {
    row_number: merged.row_number,
    BLOCKS_JSON: JSON.stringify(blocks),
    TITLE: merged.TITLE,
    SUBTITLE: merged.SUBTITLE,
    META_DESCRIPTION: merged.META_DESCRIPTION,
    FEATURE_IMAGE: featureImage,
    STATUS: 'IMAGES_DONE',
    blocks,
    feature_image: featureImage
  }
}];

